import{_ as a,o as i,c as t,a4 as s}from"./chunks/framework.CgwWDRUJ.js";const g=JSON.parse('{"title":"3. Proposed System","description":"","frontmatter":{},"headers":[],"relativePath":"rad/proposed-system/functional.md","filePath":"rad/proposed-system/functional.md"}'),r={name:"rad/proposed-system/functional.md"};function l(n,e,o,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_3-proposed-system" tabindex="-1">3. Proposed System <a class="header-anchor" href="#_3-proposed-system" aria-label="Permalink to “3. Proposed System”">​</a></h1><h2 id="_3-1-overview" tabindex="-1">3.1 Overview <a class="header-anchor" href="#_3-1-overview" aria-label="Permalink to “3.1 Overview”">​</a></h2><p>The TravelMate system is a modern, cloud-based platform built on a 3-tier architecture:</p><ul><li><strong>Presentation Layer</strong>: Flutter-based mobile app and web interface (MVVM architecture)</li><li><strong>Application Layer</strong>: Django-based REST API backend</li><li><strong>Data Layer</strong>: PostgreSQL relational database</li></ul><p>The system implements intelligent matching algorithms, secure communication channels, and comprehensive user management to create a seamless travel companion discovery and coordination experience.</p><h2 id="_3-2-functional-requirements" tabindex="-1">3.2 Functional Requirements <a class="header-anchor" href="#_3-2-functional-requirements" aria-label="Permalink to “3.2 Functional Requirements”">​</a></h2><h3 id="module-a-user-management-and-profiling" tabindex="-1">Module A: User Management and Profiling <a class="header-anchor" href="#module-a-user-management-and-profiling" aria-label="Permalink to “Module A: User Management and Profiling”">​</a></h3><h4 id="a-1-user-registration-and-authentication" tabindex="-1">A.1 User Registration and Authentication <a class="header-anchor" href="#a-1-user-registration-and-authentication" aria-label="Permalink to “A.1 User Registration and Authentication”">​</a></h4><ul><li><strong>FR-A.1.1</strong>: System shall allow unauthenticated users to register with email/password</li><li><strong>FR-A.1.2</strong>: System shall support social login (Google, Facebook)</li><li><strong>FR-A.1.3</strong>: System shall enforce password complexity requirements (minimum 8 characters, mixed case, numbers)</li><li><strong>FR-A.1.4</strong>: System shall send email verification on registration</li><li><strong>FR-A.1.5</strong>: System shall implement JWT-based authentication for secure API access</li></ul><h4 id="a-2-profile-management" tabindex="-1">A.2 Profile Management <a class="header-anchor" href="#a-2-profile-management" aria-label="Permalink to “A.2 Profile Management”">​</a></h4><ul><li><strong>FR-A.2.1</strong>: Users shall be able to create and edit their profile with: <ul><li>First name, last name, date of birth</li><li>Bio/description (max 500 characters)</li><li>Profile photo (multiple photos supported)</li><li>Gender and preferred pronouns</li><li>Location (city/country)</li></ul></li><li><strong>FR-A.2.2</strong>: System shall validate user age (minimum 18 years)</li><li><strong>FR-A.2.3</strong>: Users shall be able to upload up to 5 profile photos</li><li><strong>FR-A.2.4</strong>: System shall allow users to view and edit their profile information</li><li><strong>FR-A.2.5</strong>: System shall display profile completion percentage</li></ul><h4 id="a-3-interests-and-destinations" tabindex="-1">A.3 Interests and Destinations <a class="header-anchor" href="#a-3-interests-and-destinations" aria-label="Permalink to “A.3 Interests and Destinations”">​</a></h4><ul><li><strong>FR-A.3.1</strong>: Users shall select interests from predefined categories: <ul><li>Adventure, Relaxation, Culture, Museums, Food, Nightlife, Sports, Nature, Photography, Budget Travel, Luxury Travel, Family-Friendly, Solo Travel, Group Travel</li></ul></li><li><strong>FR-A.3.2</strong>: Users shall select multiple favorite destinations</li><li><strong>FR-A.3.3</strong>: System shall store interest-destination relationships for matching purposes</li><li><strong>FR-A.3.4</strong>: Users shall be able to update interests and destinations at any time</li></ul><h4 id="a-4-privacy-management" tabindex="-1">A.4 Privacy Management <a class="header-anchor" href="#a-4-privacy-management" aria-label="Permalink to “A.4 Privacy Management”">​</a></h4><ul><li><strong>FR-A.4.1</strong>: Users shall be able to set profile visibility (Public, Friends Only, Hidden)</li><li><strong>FR-A.4.2</strong>: Users shall have option to hide profile from search results</li><li><strong>FR-A.4.3</strong>: Users shall be able to block other users</li><li><strong>FR-A.4.4</strong>: Users shall be able to display last name only to saved matches</li><li><strong>FR-A.4.5</strong>: System shall maintain a blocked users list</li><li><strong>FR-A.4.6</strong>: Users shall be able to report abusive profiles</li><li><strong>FR-A.4.7</strong>: System shall allow data export (GDPR compliance)</li><li><strong>FR-A.4.8</strong>: System shall allow account deletion and data removal</li></ul><h3 id="module-b-search-engine-and-matching" tabindex="-1">Module B: Search Engine and Matching <a class="header-anchor" href="#module-b-search-engine-and-matching" aria-label="Permalink to “Module B: Search Engine and Matching”">​</a></h3><h4 id="b-1-travel-companion-search" tabindex="-1">B.1 Travel Companion Search <a class="header-anchor" href="#b-1-travel-companion-search" aria-label="Permalink to “B.1 Travel Companion Search”">​</a></h4><ul><li><strong>FR-B.1.1</strong>: System shall provide advanced search with filters for: <ul><li>Age range</li><li>Gender</li><li>Languages spoken</li><li>Budget level (Budget/Mid-range/Luxury)</li><li>Flexibility level (Very Flexible/Moderately Flexible/Set Plans)</li><li>Interests (multi-select)</li><li>Location</li></ul></li><li><strong>FR-B.1.2</strong>: System shall display search results with user profiles</li><li><strong>FR-B.1.3</strong>: Search results shall be sorted by compatibility score (default)</li><li><strong>FR-B.1.4</strong>: System shall support pagination (20 profiles per page)</li><li><strong>FR-B.1.5</strong>: Search response time must be &lt; 2 seconds for standard queries</li></ul><h4 id="b-2-matching-algorithm" tabindex="-1">B.2 Matching Algorithm <a class="header-anchor" href="#b-2-matching-algorithm" aria-label="Permalink to “B.2 Matching Algorithm”">​</a></h4><ul><li><strong>FR-B.2.1</strong>: System shall calculate compatibility score based on: <ul><li>Shared interests (40% weight)</li><li>Destination overlap (30% weight)</li><li>Travel style compatibility (20% weight)</li><li>Availability dates overlap (10% weight)</li></ul></li><li><strong>FR-B.2.2</strong>: System shall recommend compatible travelers in discover feed</li><li><strong>FR-B.2.3</strong>: Matching shall exclude blocked users and hidden profiles</li><li><strong>FR-B.2.4</strong>: System shall learn from user interactions to improve recommendations</li></ul><h4 id="b-3-trip-destination-search" tabindex="-1">B.3 Trip/Destination Search <a class="header-anchor" href="#b-3-trip-destination-search" aria-label="Permalink to “B.3 Trip/Destination Search”">​</a></h4><ul><li><strong>FR-B.3.1</strong>: System shall allow searching for trips by: <ul><li>Destination</li><li>Date range</li><li>Budget</li><li>Number of participants</li><li>Trip creator interests</li></ul></li><li><strong>FR-B.3.2</strong>: System shall display trip details: <ul><li>Title, description, destination</li><li>Start/end dates, budget estimate</li><li>Creator profile, participants list</li><li>Itinerary overview</li></ul></li><li><strong>FR-B.3.3</strong>: Users shall be able to request to join trips</li><li><strong>FR-B.3.4</strong>: Trip creators shall approve/reject join requests</li></ul><h3 id="module-c-interaction-and-saving" tabindex="-1">Module C: Interaction and Saving <a class="header-anchor" href="#module-c-interaction-and-saving" aria-label="Permalink to “Module C: Interaction and Saving”">​</a></h3><h4 id="c-1-saved-items" tabindex="-1">C.1 Saved Items <a class="header-anchor" href="#c-1-saved-items" aria-label="Permalink to “C.1 Saved Items”">​</a></h4><ul><li><strong>FR-C.1.1</strong>: Users shall be able to save (favorite) travel companion profiles</li><li><strong>FR-C.1.2</strong>: Users shall be able to save trips they&#39;re interested in</li><li><strong>FR-C.1.3</strong>: System shall maintain a saved items list per user</li><li><strong>FR-C.1.4</strong>: Users shall be able to view their saved items</li><li><strong>FR-C.1.5</strong>: Saved items shall be organized by type (companions/trips)</li><li><strong>FR-C.1.6</strong>: Users shall be able to unsave items</li></ul><h4 id="c-2-integrated-chat-system" tabindex="-1">C.2 Integrated Chat System <a class="header-anchor" href="#c-2-integrated-chat-system" aria-label="Permalink to “C.2 Integrated Chat System”">​</a></h4><ul><li><strong>FR-C.2.1</strong>: System shall support 1-on-1 private messaging</li><li><strong>FR-C.2.2</strong>: System shall support group messaging for trip participants</li><li><strong>FR-C.2.3</strong>: Chat messages shall include: <ul><li>Message text (max 5000 characters)</li><li>Timestamp</li><li>Read/unread status</li><li>User identification</li></ul></li><li><strong>FR-C.2.4</strong>: System shall display online/offline status</li><li><strong>FR-C.2.5</strong>: Users shall receive notifications for new messages</li><li><strong>FR-C.2.6</strong>: Users shall be able to search message history</li><li><strong>FR-C.2.7</strong>: Users shall be able to block users from initiating chats</li><li><strong>FR-C.2.8</strong>: Chat history shall be encrypted in transit and at rest</li></ul><h4 id="c-3-notifications" tabindex="-1">C.3 Notifications <a class="header-anchor" href="#c-3-notifications" aria-label="Permalink to “C.3 Notifications”">​</a></h4><ul><li><strong>FR-C.3.1</strong>: System shall send notifications for: <ul><li>New messages</li><li>Match recommendations</li><li>Trip join requests</li><li>Connection requests</li><li>Profile views</li></ul></li><li><strong>FR-C.3.2</strong>: Users shall be able to control notification preferences</li><li><strong>FR-C.3.3</strong>: System shall support push notifications on mobile</li><li><strong>FR-C.3.4</strong>: System shall support email notifications</li></ul><h3 id="module-d-trip-management" tabindex="-1">Module D: Trip Management <a class="header-anchor" href="#module-d-trip-management" aria-label="Permalink to “Module D: Trip Management”">​</a></h3><h4 id="d-1-trip-creation" tabindex="-1">D.1 Trip Creation <a class="header-anchor" href="#d-1-trip-creation" aria-label="Permalink to “D.1 Trip Creation”">​</a></h4><ul><li><strong>FR-D.1.1</strong>: Users shall be able to create trips with: <ul><li>Title, description</li><li>Destination</li><li>Start/end dates</li><li>Budget estimate</li><li>Max participants</li><li>Itinerary items</li></ul></li><li><strong>FR-D.1.2</strong>: System shall validate date ranges (start before end)</li><li><strong>FR-D.1.3</strong>: Trip creator shall be marked as organizer</li><li><strong>FR-D.1.4</strong>: System shall generate trip ID and access code</li></ul><h4 id="d-2-trip-participation" tabindex="-1">D.2 Trip Participation <a class="header-anchor" href="#d-2-trip-participation" aria-label="Permalink to “D.2 Trip Participation”">​</a></h4><ul><li><strong>FR-D.2.1</strong>: Users shall be able to join trips they&#39;re invited to</li><li><strong>FR-D.2.2</strong>: Trip creators shall approve join requests</li><li><strong>FR-D.2.3</strong>: System shall prevent exceeding max participants</li><li><strong>FR-D.2.4</strong>: System shall track all participants and their status</li></ul><h3 id="module-e-administration" tabindex="-1">Module E: Administration <a class="header-anchor" href="#module-e-administration" aria-label="Permalink to “Module E: Administration”">​</a></h3><h4 id="e-1-user-moderation" tabindex="-1">E.1 User Moderation <a class="header-anchor" href="#e-1-user-moderation" aria-label="Permalink to “E.1 User Moderation”">​</a></h4><ul><li><strong>FR-E.1.1</strong>: Administrators shall be able to view all user reports</li><li><strong>FR-E.1.2</strong>: Administrators shall be able to suspend/ban users</li><li><strong>FR-E.1.3</strong>: Administrators shall be able to delete inappropriate content</li><li><strong>FR-E.1.4</strong>: Administrators shall be able to send warnings to users</li><li><strong>FR-E.1.5</strong>: System shall maintain audit logs of all admin actions</li></ul><h4 id="e-2-system-monitoring" tabindex="-1">E.2 System Monitoring <a class="header-anchor" href="#e-2-system-monitoring" aria-label="Permalink to “E.2 System Monitoring”">​</a></h4><ul><li><strong>FR-E.2.1</strong>: Administrators shall have access to system analytics dashboard</li><li><strong>FR-E.2.2</strong>: Administrators shall view user statistics and engagement metrics</li><li><strong>FR-E.2.3</strong>: Administrators shall monitor system performance metrics</li></ul><h2 id="_3-2-9-implementation-status-repository-snapshot" tabindex="-1">3.2.9 Implementation status (repository snapshot) <a class="header-anchor" href="#_3-2-9-implementation-status-repository-snapshot" aria-label="Permalink to “3.2.9 Implementation status (repository snapshot)”">​</a></h2><p>The TravelMate GitHub repository (Simo-2004/TravelMate) is a Flutter-based MVP with a local-first architecture. The following summary maps the functional requirements above to the current codebase status (implemented / partial / planned):</p><ul><li><p>Implemented (client-side in the repository):</p><ul><li>Saved Items (FR-C.1.x): Implemented via <code>SavedTripPreviewStore</code> and <code>SavedBookmarksData</code> (see <code>lib/shared/state/saved_trip_preview_store.dart</code> and <code>lib/shared/data/saved_bookmarks_data.dart</code>).</li><li>Local Search &amp; Discovery (FR-B.1.x, FR-B.3.x partial): Client-side search and filtering for mock <code>TripCatalog</code> and <code>MateCatalog</code> are implemented in <code>lib/features/search/search_results_screen.dart</code>, <code>lib/shared/data/trip_catalog.dart</code>, and <code>lib/shared/data/mate_catalog.dart</code>.</li><li>Personal Profile (FR-A.2.x): <code>PersonalProfileStore</code> and the profile UI are implemented (<code>lib/shared/state/personal_profile_store.dart</code>, <code>lib/features/profile/personal_profile_screen.dart</code>, <code>lib/shared/models/personal_profile.dart</code>).</li><li>Privacy Settings (FR-A.4.x): Implemented via <code>PrivacySettingsStore</code> and <code>PrivacySettingsData</code> (<code>lib/shared/state/privacy_settings_store.dart</code>, <code>lib/shared/data/privacy_settings_data.dart</code>).</li><li>Presentation/UI screens and navigation (core app flows): Implemented (see <code>lib/features/*</code> and <code>lib/features/navigation/navigation_shell.dart</code>).</li></ul></li><li><p>Partial / Mock implementations:</p><ul><li>Trip data and discovery are supplied as static/mock catalogs (<code>TripCatalog</code>, <code>TripMediaCatalog</code>) rather than dynamic trip creation or server-side trip persistence.</li><li>Search ranking is implemented locally using a scoring heuristic; server-side ranking and large-scale search (Elasticsearch) are not present.</li></ul></li><li><p>Not implemented / Planned (no code in repository):</p><ul><li>Authentication (FR-A.1.x) — there is no backend auth or social login implemented in the repository.</li><li>Messaging &amp; real-time chat (FR-C.2.x) — chat and messaging systems are not implemented.</li><li>Trip creation and server-side trip lifecycle management (FR-D.1.x, FR-D.2.x) — trips are mock data; create/join flows backed by a server are planned.</li><li>Administration tools, moderation dashboards, analytics (FR-E.x) — admin backend is not implemented.</li></ul></li></ul><p>This status section is intentionally concise; specific file paths above provide direct references to the corresponding implementations in the repository.</p>',43)])])}const p=a(r,[["render",l]]);export{g as __pageData,p as default};
